#include <vector>
#include <utility>
#include <algorithm>

using namespace std;

long long solve(string s, vector<long long> order, long long k) {
    int n = s.length();
    vector<pair<int, int>> intervals;
    intervals.push_back({0, n-1});
    long long non_star = (long long)n * (n + 1) / 2;
    long long total_substrings = non_star;
    for (int t = 0; t < n; ++t) {
        int pos = order[t];
        int idx = -1;
        int low = 0, high = intervals.size() - 1;
        while (low <= high) {
            int mid = (low + high) / 2;
            if (intervals[mid].first <= pos) {
                idx = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        if (idx == -1) continue;
        if (intervals[idx].second < pos) continue;
        int a = intervals[idx].first;
        int b = intervals[idx].second;
        intervals.erase(intervals.begin() + idx);
        long long original_length = b - a + 1;
        long long original_contribution = original_length * (original_length + 1) / 2;
        vector<pair<int, int>> new_intervals;
        if (a < pos) new_intervals.push_back({a, pos - 1});
        if (b > pos) new_intervals.push_back({pos + 1, b});
        int insert_pos = idx;
        for (auto& ni : new_intervals) {
            intervals.insert(intervals.begin() + insert_pos, ni);
            insert_pos++;
        }
        non_star -= original_contribution;
        for (auto& ni : new_intervals) {
            int len = ni.second - ni.first + 1;
            long long contrib = len * (len + 1) / 2;
            non_star += contrib;
        }
        long long valid = total_substrings - non_star;
        if (valid >= k) return t;
    }
    return -1;
}
